WOMT_aTexte['popup_faq_8_text']=new Array();
WOMT_aTexte['popup_faq_8_text'][0]='Auf dem Ergebnisbildschirm sehen Sie direkt, welche der von Ihnen ausgewählten Parteien oder Wählervereinigungen Ihnen am nächsten steht. Auf der folgenden Seite finden Sie die Parteiantworten zu jeder These im Überblick ("stimme zu" = Häkchen, "stimme nicht zu" = Kreuz, "neutral" = Minuszeichen). Ein Klick auf den jeweiligen Parteinamen zeigt eine kurze Begründung der Partei für ihre Position an, sofern eine Begründung abgeben wurde.';
